import React, { useState, useEffect } from 'react';
import { 
  User, 
  UserRole, 
  Student, 
  Teacher, 
  NewsItem, 
  Notification 
} from './types';
import { 
  INITIAL_STUDENTS, 
  INITIAL_TEACHERS, 
  INITIAL_NEWS, 
  INITIAL_ADMINS 
} from './constants';
import Login from './components/Login';
import DashboardStudent from './components/DashboardStudent';
import DashboardTeacher from './components/DashboardTeacher';
import DashboardAdmin from './components/DashboardAdmin';
import { Bell, LogOut } from 'lucide-react';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [students, setStudents] = useState<Student[]>(INITIAL_STUDENTS);
  const [teachers, setTeachers] = useState<Teacher[]>(INITIAL_TEACHERS);
  const [admins, setAdmins] = useState<User[]>(INITIAL_ADMINS);
  const [news, setNews] = useState<NewsItem[]>(INITIAL_NEWS);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [showNotifications, setShowNotifications] = useState(false);

  // Load data from localStorage on mount
  useEffect(() => {
    const savedStudents = localStorage.getItem('om-abiha-students');
    const savedTeachers = localStorage.getItem('om-abiha-teachers');
    const savedNews = localStorage.getItem('om-abiha-news');
    const savedAdmins = localStorage.getItem('om-abiha-admins');
    const savedUser = localStorage.getItem('om-abiha-current-user');

    if (savedStudents) setStudents(JSON.parse(savedStudents));
    if (savedTeachers) setTeachers(JSON.parse(savedTeachers));
    if (savedNews) setNews(JSON.parse(savedNews));
    if (savedAdmins) setAdmins(JSON.parse(savedAdmins));
    if (savedUser) setCurrentUser(JSON.parse(savedUser));
  }, []);

  // Save data to localStorage on change
  useEffect(() => {
    localStorage.setItem('om-abiha-students', JSON.stringify(students));
    localStorage.setItem('om-abiha-teachers', JSON.stringify(teachers));
    localStorage.setItem('om-abiha-news', JSON.stringify(news));
    localStorage.setItem('om-abiha-admins', JSON.stringify(admins));
  }, [students, teachers, news, admins]);

  const addNotification = (userId: string, type: Notification['type'], message: string) => {
    const newNotif: Notification = {
      id: Math.random().toString(36).substr(2, 9),
      userId,
      type,
      message,
      date: new Date().toISOString()
    };
    setNotifications(prev => [newNotif, ...prev]);
  };

  const handleLogin = (name: string, code: string, role: UserRole) => {
    let foundUser: User | undefined;

    if (role === UserRole.STUDENT) {
      foundUser = students.find(s => s.name === name && s.code === code);
    } else if (role === UserRole.TEACHER) {
      foundUser = teachers.find(t => t.name === name && t.code === code);
    } else {
      foundUser = admins.find(a => a.name === name && a.code === code);
    }

    if (foundUser) {
      setCurrentUser(foundUser);
      localStorage.setItem('om-abiha-current-user', JSON.stringify(foundUser));
    } else {
      alert('الاسم أو الرمز غير صحيح');
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('om-abiha-current-user');
  };

  const renderDashboard = () => {
    if (!currentUser) return <Login onLogin={handleLogin} />;

    switch (currentUser.role) {
      case UserRole.STUDENT:
        const studentData = students.find(s => s.id === currentUser.id);
        return studentData ? <DashboardStudent student={studentData} news={news} /> : null;
      case UserRole.TEACHER:
        const teacherData = teachers.find(t => t.id === currentUser.id);
        return teacherData ? (
          <DashboardTeacher 
            teacher={teacherData} 
            students={students} 
            setStudents={setStudents}
            news={news}
            setNews={setNews}
            addNotification={addNotification}
          />
        ) : null;
      case UserRole.ADMIN:
        return (
          <DashboardAdmin 
            students={students} 
            setStudents={setStudents}
            teachers={teachers}
            setTeachers={setTeachers}
            admins={admins}
            setAdmins={setAdmins}
          />
        );
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen flex flex-col">
      {currentUser && (
        <header className="bg-teal-700 text-white p-4 shadow-md flex justify-between items-center sticky top-0 z-50">
          <div className="flex items-center gap-3">
            <div className="bg-white p-1 rounded-full overflow-hidden">
               <img src="https://picsum.photos/seed/school/40/40" alt="logo" className="w-8 h-8 rounded-full" />
            </div>
            <h1 className="text-xl font-bold hidden sm:block">بوابة أم أبيها التعليمية</h1>
          </div>
          <div className="flex items-center gap-4">
            <button 
              onClick={() => setShowNotifications(!showNotifications)}
              className="relative p-2 hover:bg-teal-600 rounded-full transition-colors"
            >
              <Bell size={24} />
              {notifications.length > 0 && (
                <span className="absolute top-0 right-0 bg-red-500 text-xs w-5 h-5 flex items-center justify-center rounded-full border-2 border-teal-700">
                  {notifications.length}
                </span>
              )}
            </button>
            <button 
              onClick={handleLogout}
              className="flex items-center gap-2 bg-teal-800 hover:bg-teal-900 px-3 py-1.5 rounded-lg transition-colors text-sm font-semibold"
            >
              <LogOut size={18} />
              <span>خروج</span>
            </button>
          </div>
        </header>
      )}

      <main className="flex-1 container mx-auto p-4 max-w-6xl">
        {renderDashboard()}
      </main>

      {/* Notifications Drawer */}
      {showNotifications && (
        <div className="fixed inset-0 z-50 overflow-hidden" onClick={() => setShowNotifications(false)}>
          <div className="absolute inset-0 bg-black bg-opacity-30 backdrop-blur-sm" />
          <div 
            className="absolute left-0 top-0 bottom-0 w-80 bg-white shadow-2xl p-4 overflow-y-auto transform transition-transform"
            onClick={e => e.stopPropagation()}
          >
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-xl font-bold text-teal-800">الإشعارات</h2>
              <button onClick={() => setShowNotifications(false)} className="text-gray-500 hover:text-gray-700">✕</button>
            </div>
            {notifications.length === 0 ? (
              <p className="text-gray-500 text-center mt-10">لا توجد إشعارات حالياً</p>
            ) : (
              <div className="space-y-4">
                {notifications.map(n => (
                  <div key={n.id} className="p-3 bg-teal-50 border-r-4 border-teal-600 rounded shadow-sm">
                    <p className="text-sm font-semibold mb-1">{n.message}</p>
                    <span className="text-xs text-gray-500">{new Date(n.date).toLocaleTimeString('ar-IQ')}</span>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      )}

      <footer className="bg-white border-t p-4 text-center text-gray-500 text-sm">
        &copy; {new Date().getFullYear()} مدرسة متوسطة أم أبيها المختلطة - جميع الحقوق محفوظة
      </footer>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { UserRole } from '../types';
import { User, ShieldCheck, GraduationCap, Users } from 'lucide-react';

interface LoginProps {
  onLogin: (name: string, code: string, role: UserRole) => void;
}

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [role, setRole] = useState<UserRole>(UserRole.STUDENT);
  const [name, setName] = useState('');
  const [code, setCode] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (name && code) {
      onLogin(name, code, role);
    }
  };

  return (
    <div className="max-w-md mx-auto mt-12 bg-white rounded-2xl shadow-xl overflow-hidden animate-fade-in">
      <div className="bg-teal-700 p-8 text-white text-center">
        <div className="w-24 h-24 bg-white/20 rounded-full flex items-center justify-center mx-auto mb-4 border-4 border-white/30">
          <GraduationCap size={48} />
        </div>
        <h2 className="text-2xl font-bold">بوابة أم أبيها التعليمية</h2>
        <p className="text-teal-100 mt-2 text-sm">تسجيل الدخول للنظام التعليمي</p>
      </div>

      <div className="p-8">
        <form onSubmit={handleSubmit} className="space-y-6">
          <div className="grid grid-cols-3 gap-2">
            {[UserRole.STUDENT, UserRole.TEACHER, UserRole.ADMIN].map((r) => (
              <button
                key={r}
                type="button"
                onClick={() => setRole(r)}
                className={`py-2 px-1 text-sm rounded-lg border transition-all flex flex-col items-center gap-1 ${
                  role === r 
                    ? 'bg-teal-50 border-teal-600 text-teal-700 ring-1 ring-teal-600' 
                    : 'bg-white border-gray-200 text-gray-500 hover:border-teal-400'
                }`}
              >
                {r === UserRole.STUDENT && <Users size={18} />}
                {r === UserRole.TEACHER && <User size={18} />}
                {r === UserRole.ADMIN && <ShieldCheck size={18} />}
                {r}
              </button>
            ))}
          </div>

          <div className="space-y-4">
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-1">الاسم الكامل</label>
              <div className="relative">
                 <input
                  type="text"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  className="w-full pl-3 pr-10 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-teal-500 focus:bg-white transition-all"
                  placeholder="أدخل اسمك كما هو مسجل"
                  required
                />
                <User className="absolute right-3 top-1/2 -translate-y-14 sm:-translate-y-1/2 text-gray-400" size={20} />
              </div>
            </div>

            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-1">الرمز الخاص</label>
              <div className="relative">
                <input
                  type="password"
                  value={code}
                  onChange={(e) => setCode(e.target.value)}
                  className="w-full pl-3 pr-10 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-teal-500 focus:bg-white transition-all"
                  placeholder="أدخل رمز الدخول"
                  required
                />
                <ShieldCheck className="absolute right-3 top-1/2 -translate-y-14 sm:-translate-y-1/2 text-gray-400" size={20} />
              </div>
            </div>
          </div>

          <button
            type="submit"
            className="w-full bg-teal-600 hover:bg-teal-700 text-white font-bold py-3 px-4 rounded-xl shadow-lg transform active:scale-95 transition-all"
          >
            دخول للنظام
          </button>
        </form>
      </div>
    </div>
  );
};

export default Login;

import React, { useState } from 'react';
import { Teacher, Student, NewsItem, UserRole } from '../types';
import { 
  Users, Star, AlertTriangle, PhoneCall, 
  StickyNote, PlusCircle, CheckCircle, Search, Filter
} from 'lucide-react';

interface Props {
  teacher: Teacher;
  students: Student[];
  setStudents: React.Dispatch<React.SetStateAction<Student[]>>;
  news: NewsItem[];
  setNews: React.Dispatch<React.SetStateAction<NewsItem[]>>;
  addNotification: (userId: string, type: 'warning' | 'parentCall' | 'attendance' | 'news', message: string) => void;
}

const DashboardTeacher: React.FC<Props> = ({ 
  teacher, students, setStudents, news, setNews, addNotification 
}) => {
  const [selectedClass, setSelectedClass] = useState(teacher.assignedClasses[0] || "");
  const [selectedStudent, setSelectedStudent] = useState<Student | null>(null);
  const [newsTitle, setNewsTitle] = useState("");
  const [newsContent, setNewsContent] = useState("");
  const [searchTerm, setSearchTerm] = useState("");

  const filteredStudents = students.filter(s => {
    const classMatch = `${s.grade} - ${s.section}` === selectedClass;
    const searchMatch = s.name.includes(searchTerm);
    return classMatch && searchMatch;
  });

  const handleRating = (studentId: string, rating: number) => {
    setStudents(prev => prev.map(s => s.id === studentId ? { ...s, rating } : s));
  };

  const addWarning = (studentId: string, reason: string) => {
    if (!reason) return;
    setStudents(prev => prev.map(s => {
      if (s.id === studentId) {
        addNotification(s.id, 'warning', `تحذير جديد: ${reason}`);
        return { 
          ...s, 
          warningsCount: s.warningsCount + 1, 
          warnings: [...s.warnings, reason] 
        };
      }
      return s;
    }));
    alert('تم إضافة التحذير بنجاح');
  };

  const requestParentCall = (studentId: string, reason: string) => {
    if (!reason) return;
    setStudents(prev => prev.map(s => {
      if (s.id === studentId) {
        addNotification(s.id, 'parentCall', `استدعاء ولي أمر: ${reason}`);
        return { ...s, parentCallRequested: true, parentCallReason: reason };
      }
      return s;
    }));
    alert('تم طلب استدعاء ولي الأمر');
  };

  const addNote = (studentId: string, note: string) => {
    if (!note) return;
    setStudents(prev => prev.map(s => {
      if (s.id === studentId) {
        return { ...s, notes: [...s.notes, note] };
      }
      return s;
    }));
    alert('تم إضافة الملاحظة');
  };

  const postNews = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newsTitle || !newsContent) return;
    const newItem: NewsItem = {
      id: Math.random().toString(36).substr(2, 9),
      teacherName: teacher.name,
      title: newsTitle,
      content: newsContent,
      date: new Date().toISOString()
    };
    setNews(prev => [newItem, ...prev]);
    addNotification('all', 'news', `خبر جديد من ${teacher.name}: ${newsTitle}`);
    setNewsTitle("");
    setNewsContent("");
    alert('تم نشر الخبر بنجاح');
  };

  return (
    <div className="space-y-6 animate-fade-in">
      {/* Welcome Section */}
      <div className="relative h-48 rounded-2xl overflow-hidden shadow-lg group">
        <img src="https://picsum.photos/seed/school-front/1200/400" alt="school" className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700" />
        <div className="absolute inset-0 bg-gradient-to-r from-teal-900/80 to-transparent flex items-center p-8">
          <div className="text-white">
            <h2 className="text-3xl font-bold mb-2">أهلاً بك، {teacher.name}</h2>
            <p className="text-teal-100 flex items-center gap-2">
              <CheckCircle size={18} /> مدرسة متوسطة أم أبيها المختلطة ترحب بك
            </p>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Student Management */}
        <div className="lg:col-span-2 space-y-6">
          <div className="bg-white rounded-2xl shadow-sm p-6 border border-gray-100">
            <div className="flex flex-col md:flex-row justify-between items-center gap-4 mb-6">
              <h3 className="text-xl font-bold flex items-center gap-2">
                <Users className="text-teal-600" size={24} /> إدارة الطلاب
              </h3>
              <div className="flex gap-2 w-full md:w-auto">
                <div className="relative flex-1">
                  <input 
                    type="text" 
                    placeholder="بحث عن طالب..." 
                    className="w-full pr-10 pl-4 py-2 bg-gray-50 border rounded-lg focus:ring-2 focus:ring-teal-500 outline-none"
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                  />
                  <Search size={18} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400" />
                </div>
                <select 
                  className="bg-gray-50 border rounded-lg px-3 py-2 outline-none focus:ring-2 focus:ring-teal-500"
                  value={selectedClass}
                  onChange={(e) => setSelectedClass(e.target.value)}
                >
                  {teacher.assignedClasses.map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </div>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-right">
                <thead className="bg-gray-50 text-gray-500 text-sm uppercase">
                  <tr>
                    <th className="p-4 rounded-r-lg">الاسم</th>
                    <th className="p-4">التقييم</th>
                    <th className="p-4">التحذيرات</th>
                    <th className="p-4 rounded-l-lg text-center">الإجراءات</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-100">
                  {filteredStudents.map(student => (
                    <tr key={student.id} className="hover:bg-teal-50/30 transition-colors">
                      <td className="p-4 font-semibold text-gray-700">{student.name}</td>
                      <td className="p-4">
                        <div className="flex gap-0.5">
                          {[1,2,3,4,5].map(star => (
                            <Star 
                              key={star} 
                              size={16} 
                              onClick={() => handleRating(student.id, star)}
                              className={`cursor-pointer transition-all ${star <= student.rating ? "fill-yellow-400 text-yellow-400" : "text-gray-300 hover:text-yellow-200"}`} 
                            />
                          ))}
                        </div>
                      </td>
                      <td className="p-4">
                        <span className={`px-2 py-1 rounded-full text-xs font-bold ${student.warningsCount > 0 ? 'bg-red-100 text-red-600' : 'bg-green-100 text-green-600'}`}>
                          {student.warningsCount} تحذير
                        </span>
                      </td>
                      <td className="p-4 flex justify-center gap-2">
                        <button 
                          onClick={() => setSelectedStudent(student)}
                          className="bg-teal-600 text-white px-3 py-1 rounded-md text-xs hover:bg-teal-700 transition-colors"
                        >
                          إدارة
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
              {filteredStudents.length === 0 && (
                <p className="text-center py-10 text-gray-400">لا يوجد طلاب مطابقين للبحث</p>
              )}
            </div>
          </div>
        </div>

        {/* Publish News Section */}
        <div className="space-y-6">
          <div className="bg-white rounded-2xl shadow-sm p-6 border border-gray-100">
            <h3 className="text-xl font-bold flex items-center gap-2 mb-6">
              <PlusCircle className="text-teal-600" size={24} /> نشر خبر جديد
            </h3>
            <form onSubmit={postNews} className="space-y-4">
              <div>
                <label className="block text-sm font-semibold text-gray-700 mb-1">عنوان الخبر</label>
                <input 
                  type="text" 
                  value={newsTitle}
                  onChange={(e) => setNewsTitle(e.target.value)}
                  className="w-full p-3 bg-gray-50 border rounded-xl outline-none focus:ring-2 focus:ring-teal-500"
                  placeholder="مثال: موعد الرحلة المدرسية"
                  required
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-gray-700 mb-1">نص الخبر</label>
                <textarea 
                  value={newsContent}
                  onChange={(e) => setNewsContent(e.target.value)}
                  rows={4}
                  className="w-full p-3 bg-gray-50 border rounded-xl outline-none focus:ring-2 focus:ring-teal-500"
                  placeholder="اكتب تفاصيل الخبر هنا..."
                  required
                />
              </div>
              <button 
