export default DashboardTeacher;

import React, { useState } from 'react';
import { User, Student, Teacher, UserRole } from '../types';
import { 
  ShieldCheck, UserPlus, GraduationCap, Users, 
  Trash2, Edit, Save, X, Eye, Key
} from 'lucide-react';

interface Props {
  students: Student[];
  setStudents: React.Dispatch<React.SetStateAction<Student[]>>;
  teachers: Teacher[];
  setTeachers: React.Dispatch<React.SetStateAction<Teacher[]>>;
  admins: User[];
  setAdmins: React.Dispatch<React.SetStateAction<User[]>>;
}

const DashboardAdmin: React.FC<Props> = ({ 
  students, setStudents, teachers, setTeachers, admins, setAdmins 
}) => {
  const [activeTab, setActiveTab] = useState<'students' | 'teachers' | 'admins'>('students');
  const [isEditing, setIsEditing] = useState<string | null>(null);
  const [editName, setEditName] = useState("");

  const [formData, setFormData] = useState({
    name: "", code: "", grade: "الأول", section: "أ", subject: "", role: UserRole.STUDENT, birthDate: ""
  });

  const handleAddUser = (e: React.FormEvent) => {
    e.preventDefault();
    const id = Math.random().toString(36).substr(2, 9);

    if (activeTab === 'students') {
      const newStudent: Student = {
        id,
        name: formData.name,
        code: formData.code,
        role: UserRole.STUDENT,
        birthDate: formData.birthDate || "2010-01-01",
        grade: formData.grade,
        section: formData.section,
        warningsCount: 0,
        warnings: [],
        attendance: { absent: 0, excused: 0, present: 0 },
        grades: { term1: null, midterm: null, term2: null },
        rating: 3,
        notes: [],
        parentCallRequested: false
      };
      setStudents(prev => [...prev, newStudent]);
    } else if (activeTab === 'teachers') {
      const newTeacher: Teacher = {
        id,
        name: formData.name,
        code: formData.code,
        role: UserRole.TEACHER,
        subject: formData.subject,
        assignedClasses: [`${formData.grade} - ${formData.section}`]
      };
      setTeachers(prev => [...prev, newTeacher]);
    } else {
      const newAdmin: User = {
        id,
        name: formData.name,
        code: formData.code,
        role: UserRole.ADMIN
      };
      setAdmins(prev => [...prev, newAdmin]);
    }
    setFormData({ name: "", code: "", grade: "الأول", section: "أ", subject: "", role: UserRole.STUDENT, birthDate: "" });
    alert('تمت الإضافة بنجاح');
  };

  const deleteUser = (id: string, role: UserRole) => {
    if (confirm('هل أنت متأكد من الحذف؟')) {
      if (role === UserRole.STUDENT) setStudents(prev => prev.filter(u => u.id !== id));
      else if (role === UserRole.TEACHER) setTeachers(prev => prev.filter(u => u.id !== id));
      else setAdmins(prev => prev.filter(u => u.id !== id));
    }
  };

  const startEdit = (user: User) => {
    setIsEditing(user.id);
    setEditName(user.name);
  };

  const saveEdit = (id: string, role: UserRole) => {
    if (role === UserRole.STUDENT) setStudents(prev => prev.map(u => u.id === id ? { ...u, name: editName } : u));
    else if (role === UserRole.TEACHER) setTeachers(prev => prev.map(u => u.id === id ? { ...u, name: editName } : u));
    else setAdmins(prev => prev.map(u => u.id === id ? { ...u, name: editName } : u));
    setIsEditing(null);
  };

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="bg-white rounded-2xl shadow-sm p-6 border border-teal-100 flex justify-between items-center">
        <h2 className="text-2xl font-bold text-gray-800 flex items-center gap-3">
          <ShieldCheck className="text-teal-600" size={32} /> لوحة الإدارة المركزية
        </h2>
        <div className="text-sm text-gray-500 font-mono bg-gray-100 px-3 py-1 rounded">ADMIN MODE</div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        {/* Sidebar Tabs */}
        <div className="space-y-2">
          <button 
            onClick={() => setActiveTab('students')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${activeTab === 'students' ? 'bg-teal-600 text-white shadow-lg' : 'bg-white text-gray-600 hover:bg-teal-50'}`}
          >
            <Users size={20} /> إدارة الطلاب ({students.length})
          </button>
          <button 
            onClick={() => setActiveTab('teachers')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${activeTab === 'teachers' ? 'bg-teal-600 text-white shadow-lg' : 'bg-white text-gray-600 hover:bg-teal-50'}`}
          >
            <GraduationCap size={20} /> إدارة المدرسين ({teachers.length})
          </button>
          <button 
            onClick={() => setActiveTab('admins')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${activeTab === 'admins' ? 'bg-teal-600 text-white shadow-lg' : 'bg-white text-gray-600 hover:bg-teal-50'}`}
          >
            <ShieldCheck size={20} /> إدارة الأدمن ({admins.length})
          </button>
        </div>

        {/* Main Admin View */}
        <div className="lg:col-span-3 space-y-6">
          {/* Add New User Form */}
          <div className="bg-white rounded-2xl shadow-sm p-6 border border-gray-100">
            <h3 className="text-xl font-bold mb-6 flex items-center gap-2">
              <UserPlus className="text-teal-600" size={24} /> 
              إضافة {activeTab === 'students' ? 'طالب' : activeTab === 'teachers' ? 'مدرس' : 'أدمن'} جديد
            </h3>
            <form onSubmit={handleAddUser} className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="text-xs font-bold text-gray-500">الاسم الكامل</label>
                <input 
                  type="text" 
                  value={formData.name}
                  onChange={(e) => setFormData({...formData, name: e.target.value})}
                  className="w-full p-2.5 bg-gray-50 border rounded-lg outline-none focus:ring-2 focus:ring-teal-500" 
                  required 
                />
              </div>
              <div className="space-y-1">
                <label className="text-xs font-bold text-gray-500">رمز الدخول</label>
                <input 
                  type="text" 
                  value={formData.code}
                  onChange={(e) => setFormData({...formData, code: e.target.value})}
                  className="w-full p-2.5 bg-gray-50 border rounded-lg outline-none focus:ring-2 focus:ring-teal-500 font-mono" 
                  required 
                />
              </div>

              {activeTab === 'students' && (
                <>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-gray-500">تاريخ الميلاد</label>
                    <input 
                      type="date" 
                      value={formData.birthDate}
                      onChange={(e) => setFormData({...formData, birthDate: e.target.value})}
                      className="w-full p-2.5 bg-gray-50 border rounded-lg outline-none focus:ring-2 focus:ring-teal-500" 
                    />
                  </div>
                  <div className="grid grid-cols-2 gap-2">
                    <div className="space-y-1">
                      <label className="text-xs font-bold text-gray-500">الصف</label>
                      <select 
                        value={formData.grade}
                        onChange={(e) => setFormData({...formData, grade: e.target.value})}
                        className="w-full p-2.5 bg-gray-50 border rounded-lg outline-none focus:ring-2 focus:ring-teal-500"
                      >
                        <option>الأول</option><option>الثاني</option><option>الثالث</option>
                      </select>
                    </div>
                    <div className="space-y-1">
                      <label className="text-xs font-bold text-gray-500">الشعبة</label>
                      <select 
                        value={formData.section}
                        onChange={(e) => setFormData({...formData, section: e.target.value})}
                        className="w-full p-2.5 bg-gray-50 border rounded-lg outline-none focus:ring-2 focus:ring-teal-500"
                      >
                        <option>أ</option><option>ب</option><option>ج</option><option>د</option>
                      </select>
                    </div>
                  </div>
                </>
              )}

              {activeTab === 'teachers' && (
                <>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-gray-500">المادة الدراسية</label>
                    <input 
                      type="text" 
                      value={formData.subject}
                      onChange={(e) => setFormData({...formData, subject: e.target.value})}
                      className="w-full p-2.5 bg-gray-50 border rounded-lg outline-none focus:ring-2 focus:ring-teal-500" 
                      placeholder="مثال: اللغة العربية"
                    />
                  </div>
                  <div className="grid grid-cols-2 gap-2">
                    <div className="space-y-1">
                      <label className="text-xs font-bold text-gray-500">الصف الأساسي</label>
                      <select 
                        value={formData.grade}
                        onChange={(e) => setFormData({...formData, grade: e.target.value})}
                        className="w-full p-2.5 bg-gray-50 border rounded-lg outline-none focus:ring-2 focus:ring-teal-500"
                      >
                        <option>الأول</option><option>الثاني</option><option>الثالث</option>
                      </select>
                    </div>
                    <div className="space-y-1">
                      <label className="text-xs font-bold text-gray-500">الشعبة</label>
                      <select 
                        value={formData.section}
                        onChange={(e) => setFormData({...formData, section: e.target.value})}
                        className="w-full p-2.5 bg-gray-50 border rounded-lg outline-none focus:ring-2 focus:ring-teal-500"
                      >
                        <option>أ</option><option>ب</option><option>ج</option><option>د</option>
                      </select>
                    </div>
                  </div>
                </>
              )}

              <div className="md:col-span-2 pt-2">
                <button type="submit" className="w-full bg-teal-600 text-white font-bold py-3 rounded-xl hover:bg-teal-700 transition-all flex items-center justify-center gap-2">
                  <UserPlus size={20} /> تأكيد الإضافة
                </button>
              </div>
            </form>
          </div>

          {/* User List Management */}
          <div className="bg-white rounded-2xl shadow-sm p-6 border border-gray-100">
            <h3 className="text-xl font-bold mb-4">قائمة المسجلين</h3>
            <div className="overflow-x-auto">
              <table className="w-full text-right">
                <thead className="bg-gray-50 text-gray-500 text-sm">
                  <tr>
                    <th className="p-4 rounded-r-lg">الاسم</th>
                    <th className="p-4">الرمز</th>
                    <th className="p-4">التفاصيل</th>
                    <th className="p-4 rounded-l-lg text-center">الإجراءات</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-100">
                  {(activeTab === 'students' ? students : activeTab === 'teachers' ? teachers : admins).map(user => (
                    <tr key={user.id} className="hover:bg-gray-50">
                      <td className="p-4">
                        {isEditing === user.id ? (
                          <input 
                            type="text" 
                            value={editName}
                            onChange={(e) => setEditName(e.target.value)}
                            className="p-1 border rounded outline-none focus:ring-1 focus:ring-teal-500"
                          />
                        ) : (
                          <span className="font-semibold">{user.name}</span>
                        )}
                      </td>
                      <td className="p-4 font-mono text-gray-500 text-sm">
                        <div className="flex items-center gap-1">
                          <Key size={14} /> {user.code}
