                      </td>
                      <td className="p-4 text-xs text-gray-400">
                        {activeTab === 'students' && `${(user as Student).grade} - ${(user as Student).section}`}
                        {activeTab === 'teachers' && (user as Teacher).subject}
                        {activeTab === 'admins' && 'التحكم الكامل'}
                      </td>
                      <td className="p-4 flex justify-center gap-2">
                        {isEditing === user.id ? (
                          <>
                            <button onClick={() => saveEdit(user.id, user.role)} className="p-1.5 text-green-600 hover:bg-green-50 rounded"><Save size={18}/></button>
                            <button onClick={() => setIsEditing(null)} className="p-1.5 text-gray-600 hover:bg-gray-50 rounded"><X size={18}/></button>
                          </>
                        ) : (
                          <>
                            <button onClick={() => startEdit(user)} className="p-1.5 text-blue-600 hover:bg-blue-50 rounded"><Edit size={18}/></button>
                            <button onClick={() => deleteUser(user.id, user.role)} className="p-1.5 text-red-600 hover:bg-red-50 rounded"><Trash2 size={18}/></button>
