import React, { useState, useEffect } from 'react';
import { 
  User, 
  UserRole, 
  Student, 
  Teacher, 
  NewsItem, 
  Notification 
} from './types';
import { 
  INITIAL_STUDENTS, 
  INITIAL_TEACHERS, 
  INITIAL_NEWS, 
  INITIAL_ADMINS 
} from './constants';
import Login from './components/Login';
import DashboardStudent from './components/DashboardStudent';
import DashboardTeacher from './components/DashboardTeacher';
import DashboardAdmin from './components/DashboardAdmin';
import { Bell, LogOut } from 'lucide-react';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [students, setStudents] = useState<Student[]>(INITIAL_STUDENTS);
  const [teachers, setTeachers] = useState<Teacher[]>(INITIAL_TEACHERS);
  const [admins, setAdmins] = useState<User[]>(INITIAL_ADMINS);
  const [news, setNews] = useState<NewsItem[]>(INITIAL_NEWS);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [showNotifications, setShowNotifications] = useState(false);

  // Load data from localStorage on mount
  useEffect(() => {
    const savedStudents = localStorage.getItem('om-abiha-students');
    const savedTeachers = localStorage.getItem('om-abiha-teachers');
    const savedNews = localStorage.getItem('om-abiha-news');
    const savedAdmins = localStorage.getItem('om-abiha-admins');
    const savedUser = localStorage.getItem('om-abiha-current-user');

    if (savedStudents) setStudents(JSON.parse(savedStudents));
    if (savedTeachers) setTeachers(JSON.parse(savedTeachers));
    if (savedNews) setNews(JSON.parse(savedNews));
    // Ensure we don't accidentally wipe out the super admin if storage was empty
    if (savedAdmins) {
      const parsedAdmins = JSON.parse(savedAdmins);
      if (parsedAdmins.length > 0) setAdmins(parsedAdmins);
    }
    if (savedUser) setCurrentUser(JSON.parse(savedUser));
  }, []);

  // Save data to localStorage on change
  useEffect(() => {
    localStorage.setItem('om-abiha-students', JSON.stringify(students));
    localStorage.setItem('om-abiha-teachers', JSON.stringify(teachers));
    localStorage.setItem('om-abiha-news', JSON.stringify(news));
    localStorage.setItem('om-abiha-admins', JSON.stringify(admins));
  }, [students, teachers, news, admins]);

  const addNotification = (userId: string, type: Notification['type'], message: string) => {
    const newNotif: Notification = {
      id: Math.random().toString(36).substr(2, 9),
      userId,
      type,
      message,
      date: new Date().toISOString()
    };
    setNotifications(prev => [newNotif, ...prev]);
  };

  const handleLogin = (name: string, code: string, role: UserRole) => {
    const trimmedName = name.trim();
    const trimmedCode = code.trim();

    let foundUser: User | undefined;

    if (role === UserRole.STUDENT) {
      foundUser = students.find(s => s.name === trimmedName && s.code === trimmedCode);
    } else if (role === UserRole.TEACHER) {
      foundUser = teachers.find(t => t.name === trimmedName && t.code === trimmedCode);
    } else {
      foundUser = admins.find(a => a.name === trimmedName && a.code === trimmedCode);
    }

    if (foundUser) {
      setCurrentUser(foundUser);
      localStorage.setItem('om-abiha-current-user', JSON.stringify(foundUser));
    } else {
      alert('الاسم أو الرمز غير صحيح لهذا النوع من المستخدمين');
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('om-abiha-current-user');
  };

  const renderDashboard = () => {
    if (!currentUser) return <Login onLogin={handleLogin} />;

    switch (currentUser.role) {
      case UserRole.STUDENT:
        const studentData = students.find(s => s.id === currentUser.id);
        return studentData ? <DashboardStudent student={studentData} news={news} /> : null;
      case UserRole.TEACHER:
        const teacherData = teachers.find(t => t.id === currentUser.id);
        return teacherData ? (
          <DashboardTeacher 
            teacher={teacherData} 
            students={students} 
            setStudents={setStudents}
            news={news}
            setNews={setNews}
            addNotification={addNotification}
          />
        ) : null;
      case UserRole.ADMIN:
        return (
          <DashboardAdmin 
            students={students} 
            setStudents={setStudents}
            teachers={teachers}
            setTeachers={setTeachers}
            admins={admins}
            setAdmins={setAdmins}
          />
        );
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen flex flex-col">
      {currentUser && (
        <header className="bg-teal-700 text-white p-4 shadow-md flex justify-between items-center sticky top-0 z-50">
          <div className="flex items-center gap-3">
            <div className="bg-white p-1 rounded-full overflow-hidden shadow-inner">
               <img src="https://picsum.photos/seed/school-logo/80/80" alt="logo" className="w-8 h-8 rounded-full" />
            </div>
            <div>
              <h1 className="text-xl font-bold hidden sm:block leading-none">بوابة أم أبيها التعليمية</h1>
              <p className="text-[10px] text-teal-200 hidden sm:block mt-1">المتوسطة المختلطة</p>
            </div>
          </div>
          <div className="flex items-center gap-4">
            <button 
              onClick={() => setShowNotifications(!showNotifications)}
              className="relative p-2 hover:bg-teal-600 rounded-full transition-colors group"
            >
              <Bell size={24} className="group-hover:rotate-12 transition-transform" />
              {notifications.length > 0 && (
                <span className="absolute top-0 right-0 bg-red-500 text-white text-[10px] w-5 h-5 flex items-center justify-center rounded-full border-2 border-teal-700 animate-bounce">
                  {notifications.length}
                </span>
              )}
            </button>
            <div className="h-8 w-[1px] bg-teal-600 mx-1"></div>
            <button 
              onClick={handleLogout}
              className="flex items-center gap-2 bg-teal-800 hover:bg-red-700 px-4 py-2 rounded-xl transition-all text-sm font-semibold shadow-inner"
            >
              <LogOut size={18} />
              <span className="hidden xs:inline">خروج</span>
            </button>
          </div>
        </header>
      )}

      <main className="flex-1 container mx-auto p-4 max-w-6xl animate-fade-in">
        {renderDashboard()}
      </main>

      {showNotifications && (
        <div className="fixed inset-0 z-[100] overflow-hidden" onClick={() => setShowNotifications(false)}>
          <div className="absolute inset-0 bg-black/40 backdrop-blur-sm transition-opacity" />
          <div 
            className="absolute left-0 top-0 bottom-0 w-80 bg-white shadow-2xl p-6 overflow-y-auto transform transition-transform border-r border-teal-100"
            onClick={e => e.stopPropagation()}
          >
            <div className="flex justify-between items-center mb-8">
              <div>
                <h2 className="text-2xl font-bold text-teal-800">التنبيهات</h2>
                <div className="h-1 w-12 bg-teal-500 rounded-full mt-1"></div>
              </div>
              <button onClick={() => setShowNotifications(false)} className="text-gray-400 hover:text-red-500 transition-colors bg-gray-100 p-2 rounded-full">
                <LogOut size={18} />
              </button>
            </div>
            {notifications.length === 0 ? (
              <div className="text-center mt-20">
                <div className="bg-gray-50 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-4">
                  <Bell size={32} className="text-gray-300" />
                </div>
                <p className="text-gray-400 font-medium">لا توجد إشعارات حالياً</p>
              </div>
            ) : (
              <div className="space-y-4">
                {notifications.map(n => (
                  <div key={n.id} className="p-4 bg-white border border-gray-100 border-r-4 border-r-teal-600 rounded-xl shadow-sm hover:shadow-md transition-shadow">
                    <p className="text-sm font-bold text-gray-800 mb-1 leading-relaxed">{n.message}</p>
                    <span className="text-[10px] text-gray-400 block">{new Date(n.date).toLocaleString('ar-IQ')}</span>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      )}

      <footer className="bg-white border-t p-6 text-center text-gray-400 text-xs">
        <p className="mb-1 font-semibold">بوابة أم أبيها التعليمية &copy; {new Date().getFullYear()}</p>
        <p>مصمم لخدمة الطلاب والملاكات التدريسية</p>
      </footer>
    </div>
  );
};

